<?php
declare(strict_types=1);
require_once __DIR__ . '/includes/public_document_security.php';
protect_customer_document_response();
require_once __DIR__ . '/admin/includes/documents_helpers.php';
require_once __DIR__ . '/includes/customer_document_acceptance.php';
documents_ensure_structure();
$token=safe_text($_GET['token']??'');$challan=documents_get_challan_by_public_token($token);
$eligible=$challan&&!empty($challan['public_share_enabled'])&&((string)($challan['dispatch_status']??'')==='dispatched'||!empty($challan['customer_acceptance']['confirmed_at']))&&!in_array((string)($challan['status']??''),['archived','cancelled'],true)&&empty($challan['archived_flag']);
if(!$eligible){http_response_code(404);exit('Document unavailable.');}
$dispatchAdvice=documents_get_dispatch_advice((string)($challan['dispatch_advice_id']??''));
if(empty($challan['customer_acceptance_request']['token_hash'])){$acceptToken=customer_acceptance_issue_token($challan,'challan');documents_save_challan($challan);}else{$acceptToken=(string)($_POST['acceptance_token']??'');}
$error='';$success=!empty($challan['customer_acceptance']['confirmed_at']);
if(isset($_GET['log_whatsapp'])&&$success){$msg=customer_acceptance_build_whatsapp_message((array)$challan['customer_acceptance'],documents_challan_public_url($challan));customer_acceptance_mark_whatsapp_opened($challan,$msg);documents_save_challan($challan);http_response_code(204);exit;}
if($_SERVER['REQUEST_METHOD']==='POST'&&!$success){$result=customer_acceptance_check_submission($challan,'challan',$_POST,$acceptToken,['ip'=>$_SERVER['REMOTE_ADDR']??'','user_agent'=>$_SERVER['HTTP_USER_AGENT']??'','salt'=>(string)($challan['id']??'')]);if(!empty($result['ok'])){$challan['customer_receipt_status']='customer_received';$challan['workflow_status']='delivered';$challan['delivered_at']=$challan['customer_acceptance']['confirmed_at']??date('c');$challan['delivery_issue_remarks']=(string)($challan['customer_acceptance']['customer_remarks']??'');$challan['delivery_issue_flag']=$challan['delivery_issue_remarks']!=='';$saved=documents_save_challan($challan);$success=(bool)($saved['ok']??false);if(!$success)$error='Unable to record confirmation. Please try again.';}else{if(!empty($result['save']))documents_save_challan($challan);$error=(string)$result['message'];}}
$items=documents_normalize_challan_items((array)($challan['items']??[]));$e=(array)($challan['customer_acceptance']??[]);$public=documents_challan_public_url($challan);$wa=customer_acceptance_whatsapp_url($e,$public);$log='challan-public.php?'.http_build_query(['token'=>$token,'log_whatsapp'=>'1']);
function ph($v): string {return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="robots" content="noindex,nofollow,noarchive"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Delivery Challan</title><style>body{font:16px Arial;background:#f4f7f6;color:#16332e;margin:0}.wrap{max-width:900px;margin:30px auto;padding:0 16px}.card{background:#fff;border-radius:16px;padding:24px;margin:16px 0;box-shadow:0 10px 30px #0001}.brand{display:flex;justify-content:space-between;gap:12px}.muted{color:#60756f}.btn{display:inline-block;background:#087b61;color:#fff;border:0;border-radius:9px;padding:12px 18px;text-decoration:none}table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid #dfe9e5;padding:10px;text-align:left}input,textarea{box-sizing:border-box;width:100%;padding:10px;margin-top:6px}.err{color:#a21b1b}.badge{background:#ecfdf5;color:#087b61;border-radius:999px;padding:5px 10px}</style></head><body><main class="wrap"><section class="card brand"><div><p class="muted">Dakshayani Enterprises</p><h1>Delivery Challan <?=ph($challan['challan_no']??$challan['dc_number']??'')?></h1><p>Quotation <?=ph($challan['linked_quote_no']??'')?> · Dispatch Advice <?=ph($challan['dispatch_advice_no']??'')?></p></div><span class="badge"><?= $success?'Delivered':'Dispatched' ?></span></section><section class="card"><h2>Delivery details</h2><p><strong>Customer:</strong> <?=ph($challan['customer_snapshot']['name']??'')?> (<?=ph(customer_acceptance_mask_mobile((string)($challan['customer_snapshot']['mobile']??'')))?>)</p><p><strong>Dispatch date:</strong> <?=ph($challan['delivery_date']??'')?> <?=ph($challan['dispatch_time']??'')?></p><p><strong>Delivery address:</strong> <?=ph($challan['delivery_address']??'')?></p><p><strong>Vehicle / transporter:</strong> <?=ph(trim(($challan['vehicle_no']??'').' '.($challan['driver_name']??'')))?></p></section><section class="card"><h2>Material list</h2><table><thead><tr><th>#</th><th>Item</th><th>Description</th><th>Brand/model</th><th>Qty</th><th>Unit</th><th>Remarks</th></tr></thead><tbody><?php foreach($items as $i=>$it):?><tr><td><?=$i+1?></td><td><?=ph($it['name']??'')?></td><td><?=ph($it['description']??'')?></td><td><?=ph($it['brand_model']??'')?></td><td><?=ph($it['qty']??'')?></td><td><?=ph($it['unit']??'')?></td><td><?=ph($it['remarks']??'')?></td></tr><?php endforeach;?></tbody></table></section><section class="card"><?php if($success):?><h2>Delivery confirmed</h2><p>Reference <?=ph($e['acceptance_ref']??'')?> · <?=ph($e['confirmed_at']??'')?></p><?php if(!empty($e['customer_remarks'])):?><p><strong>Customer remarks:</strong> <?=ph($e['customer_remarks'])?></p><p class="badge">Delivery issue reported</p><?php endif;?><a class="btn" href="<?=ph($wa)?>" onclick="try{navigator.sendBeacon('<?=ph($log)?>')}catch(e){}" target="_blank" rel="noopener">Open WhatsApp to send confirmation</a><?php else:?><h2>Confirm Delivery</h2><p class="muted">Saved mobile: <?=ph(customer_acceptance_mask_mobile((string)($challan['customer_snapshot']['mobile']??'')))?>. Enter the first 6 digits of your registered mobile to confirm receipt.</p><?php if($error):?><p class="err"><?=ph($error)?></p><?php endif;?><form method="post"><input type="hidden" name="acceptance_token" value="<?=ph($acceptToken)?>"><label>First 6 digits of registered mobile<input name="mobile_first6" inputmode="numeric" pattern="[0-9]{6}" autocomplete="off" required></label><label>Remarks (optional: missing item, damaged item, quantity difference, other delivery issue)<textarea name="remarks"></textarea></label><label><input type="checkbox" name="confirmed" value="1" required style="width:auto"> <?=ph(customer_acceptance_confirmation_text('challan'))?></label><button class="btn">Confirm Delivery</button></form><?php endif;?></section></main></body></html>
